    blocks: [
      { t: 'p', text: 'Effective gesture recognition design uses gestures deliberately distinct from natural, everyday movement (reducing false-positive triggers), provides clear feedback confirming a gesture was recognized, and offers a fallback input method for situations where recognition genuinely fails.' },
    ],
