  m0652: {
    id: 'm0652', bookId: 'master', bookLabel: 'Master Index · Visual Design', chapter: 'Visual Design',
    title: 'Glassmorphism',
    def: 'A visual style using translucent, frosted-glass-like surfaces with background blur, subtle borders, and soft shadows to create a sense of depth and layered hierarchy.',
    why: 'Glassmorphism can create an elegant sense of depth and layering, but it also carries genuine accessibility risk since translucent surfaces can reduce text contrast against varied background content.',
    blocks: [
      { t: 'p', text: 'Responsible glassmorphism use tests contrast against the full range of possible background content a translucent surface might sit over, uses it sparingly for select elements rather than throughout an entire interface, and provides a solid-background fallback where contrast can\'t be reliably guaranteed.' },
    ],
    examples: [
      { label: 'Example · Contrast-tested glassmorphism use', text: 'A team applied glassmorphism to a single modal overlay and tested text contrast against the full range of possible background content behind it, adjusting blur and opacity until contrast passed reliably.' },
      { label: 'Example · Untested glassmorphism use', text: 'A team applied a translucent glass effect throughout their interface without testing contrast against varied backgrounds, and text became genuinely unreadable over certain background content.' },
    ],
    mistake: 'Applying a translucent glass effect without testing text contrast against the full range of real background content — this is a common, easily-missed accessibility failure.',
    interview: 'Explaining how you\'d test and ensure contrast in a glassmorphic design shows accessibility-aware use of a visually striking but risky trend.',
    related: ['m0653'],
  },
