    examples: [
      { label: 'Example · Version-aware design system consumption', text: 'A design team reviewed the changelog carefully before adopting a major version bump of their component library, anticipating breaking changes that might require updating existing designs.' },
      { label: 'Example · Version-unaware design system consumption', text: 'A design team adopted a major version bump of their component library without reviewing the changelog, and existing designs broke unexpectedly due to breaking changes they hadn\'t anticipated.' },
    ],
