    blocks: [
      { t: 'p', text: 'Effective design participation in code review means reviewing a pull request\'s visual result against the intended design spec before it merges, and providing specific, actionable feedback tied to the design spec rather than a vague, subjective comment that\'s hard for an engineer to act on.' },
    ],
